import java.util.HashSet;
import java.util.ArrayList;
import java.util.Set;
import java.util.List;

public class Solution {
    public static String[] solve(String s) {
        Set<String> seen = new HashSet<>();
        List<String> segments = new ArrayList<>();
        int current_start = 0;
        while (current_start < s.length()) {
            StringBuilder current_segment = new StringBuilder();
            while (current_start < s.length()) {
                current_segment.append(s.charAt(current_start));
                if (!seen.contains(current_segment.toString())) {
                    seen.add(current_segment.toString());
                    segments.add(current_segment.toString());
                    current_start++;
                    break;
                } else {
                    current_start++;
                }
            }
        }
        return segments.toArray(new String[0]);
    }
}
